const output = [];
for (let i = 0; i < $input.all().length; i++) {
  const item = $input.all()[i];
  try {
    const buffer = await this.helpers.getBinaryDataBuffer(i, 'data');
    const text = buffer.toString('utf8').replace(/^\uFEFF/, '');
    output.push({ json: { ...item.json, caption_result: JSON.parse(text) }, binary: item.binary, pairedItem: { item: i } });
  } catch (e) {
    output.push({ json: { ...item.json, caption_result: null, parse_error: e.message || 'Gagal parse caption_result.json' }, binary: item.binary, pairedItem: { item: i } });
    continue;
  }
}
return output;

const fs = require('fs');
const output = [];

for (const item of $input.all()) {
  const caption = item.json.caption_result || {};
  if (caption.status !== 'CAPTION_GENERATED') continue;
  if (!caption.manifest_path) continue;

  const clips = caption.clip_caption_pack || [];
  const jobId = caption.job_id;
  const manifestPath = caption.manifest_path.replace(/^\.\//,'').replace(/\\/g,'/');
  const jobDir = '/files/' + manifestPath.replace(/^shared\//, '').replace(/\/manifest\.json$/, '');

  for (const clip of clips) {
    const clipIndex = clip.clip_index || 1;
    const padded = String(clipIndex).padStart(2, '0');
    const resultFile = jobDir + '/tiktok_publish_result_clip_' + padded + '.json';

    // Skip clips already handed off to Zernio or published unless an explicit canary rerun is requested.
    if (fs.existsSync(resultFile)) {
      try {
        const existing = JSON.parse(fs.readFileSync(resultFile, 'utf8'));
        const completed = ['TIKTOK_DRAFT_CREATED', 'TIKTOK_PUBLISHED', 'TIKTOK_UPLOADED'].includes(existing.status);
        if (completed && existing.force_rerun !== true) continue;
      } catch (e) {}
    }

    const captions = Array.isArray(clip.captions) ? clip.captions : [];
    const tiktokCap = captions.find(c => c.platform === 'tiktok') || captions[0] || {};
    const captionText = tiktokCap.caption || '';
    const hashtags = Array.isArray(tiktokCap.hashtags) ? tiktokCap.hashtags : [];
    const fullCaption = [captionText, hashtags.join(' ')].filter(Boolean).join(' ').trim();

    const clipFileName = clip.file_name || ('clip_' + clipIndex + '.mp4');
    const clipPath = jobDir + '/' + clipFileName;

    output.push({
      json: {
        job_id: jobId,
        clip_id: 'clip_' + padded,
        clip_index: clipIndex,
        clip_path: clipPath,
        clip_file_name: clipFileName,
        caption_full: fullCaption,
        result_path: resultFile,
        gdrive_folder_id: '180muUbpoFBBu_9Mo0Xe-VnxpIHNL2lhF',
      }
    });
    // Upload one clip per schedule to avoid overlapping large Drive uploads on a local connection.
    if (output.length >= 1) return output;
  }
}

if (output.length === 0) {
  return [{ json: { status: 'NOTHING_TO_UPLOAD' } }];
}
return output;

const sourceItems = $('Build Upload Items').all();
const output = [];

for (let index = 0; index < $input.all().length; index++) {
  const item = $input.all()[index];
  const source = sourceItems[index] ? sourceItems[index].json : {};
  const video = item.binary && item.binary.data;
  if (!video) {
    throw new Error('Binary video tidak ditemukan untuk clip: ' + (source.clip_path || item.json.clip_path || 'unknown'));
  }

  const fileName = String(source.clip_file_name || item.json.clip_file_name || video.fileName || '').trim();
  if (!fileName.toLowerCase().endsWith('.mp4')) {
    throw new Error('Clip harus berupa MP4 sebelum upload Google Drive: ' + (fileName || source.clip_path || item.json.clip_path || 'unknown'));
  }

  // Materialize one stream at a time so Google Drive uses media upload with Content-Type video/mp4.
  // Keeping the n8n binary storage id triggers resumable upload without the correct MIME header in n8n 1.94.1.
  const buffer = await this.helpers.getBinaryDataBuffer(index, 'data');

  output.push({
    json: {
      ...source,
      ...item.json,
      fileName,
      fileExtension: 'mp4',
      mimeType: 'video/mp4',
    },
    binary: {
      data: {
        data: buffer.toString('base64'),
        fileName,
        fileExtension: 'mp4',
        mimeType: 'video/mp4',
      },
    },
    pairedItem: { item: index },
  });
}

return output;

const sourceItems = $('Normalize Video Binary').all();

return $input.all().map((item, index) => {
  const source = sourceItems[index];
  const location = item.json && item.json.headers && item.json.headers.location;
  if (!location) {
    throw new Error('Google Drive tidak mengembalikan resumable session URI.');
  }
  if (!source || !source.binary || !source.binary.data) {
    throw new Error('Binary video hilang sebelum resumable upload.');
  }

  return {
    json: {
      ...source.json,
      resumable_upload_url: location,
    },
    binary: source.binary,
    pairedItem: { item: index },
  };
});

return $input.all().map((item, index) => {
  const mimeType = String(item.json.mimeType || '').toLowerCase();
  if (mimeType !== 'video/mp4') {
    throw new Error('Google Drive menyimpan file dengan MIME type yang salah: ' + (mimeType || 'unknown') + '. Expected: video/mp4');
  }

  return {
    json: item.json,
    binary: item.binary,
    pairedItem: { item: index },
  };
});

const fs = require('fs');
const clipItems = $('Normalize Video Binary').all();
const driveItems = $('Upload to GDrive').all();
const output = [];

let apiKey = '';
try {
  if (fs.existsSync('/files/config/zernio_api_key.txt')) {
    apiKey = fs.readFileSync('/files/config/zernio_api_key.txt', 'utf8').trim();
  }
} catch (e) {}
if (!apiKey) apiKey = String(process.env.ZERNIO_API_KEY || '').trim();
if (!apiKey) throw new Error('Zernio API key tidak ditemukan di file maupun environment variable ZERNIO_API_KEY.');

let accountId = '';
try {
  if (fs.existsSync('/files/config/wf05_manual_gdrive.json')) {
    const wfConfig = JSON.parse(fs.readFileSync('/files/config/wf05_manual_gdrive.json', 'utf8'));
    accountId = String(wfConfig.zernio_tiktok_account_id || '').trim();
  }
} catch (e) {}
if (!accountId) accountId = String(process.env.ZERNIO_TIKTOK_ACCOUNT_ID || '').trim();
if (!accountId) throw new Error('zernio_tiktok_account_id tidak ditemukan di config maupun environment.');

for (let i = 0; i < clipItems.length; i++) {
  const original = clipItems[i].json;
  const driveResponse = driveItems[i] ? driveItems[i].json : {};
  const fileId = driveResponse.id || '';
  const videoUrl = fileId ? 'https://drive.google.com/uc?export=download&id=' + fileId : '';

  let response;
  try {
    response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://zernio.com/api/v1/posts',
    headers: {
      'Authorization': 'Bearer ' + apiKey,
      'Content-Type': 'application/json',
    },
    body: {
      content: original.caption_full || '',
      mediaItems: [{url: videoUrl, type: 'video'}],
      platforms: [{platform: 'tiktok', accountId: accountId}],
    },
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
  });

    });
  } catch (httpError) {
    response = { statusCode: 0, body: { error: httpError.message || 'HTTP request failed' } };
  }
  const statusCode = response.statusCode || 0;
  const result = {
    status: statusCode >= 200 && statusCode < 300 ? 'TIKTOK_DRAFT_CREATED' : 'TIKTOK_PUBLISH_FAILED',
    published_at: new Date().toISOString(),
    job_id: original.job_id,
    clip_id: original.clip_id,
    clip_index: original.clip_index,
    video_url: videoUrl,
    gdrive_file_id: fileId,
    gdrive_mime_type: driveResponse.mimeType || '',
    caption: original.caption_full,
    zernio_status: statusCode,
    zernio_response: response.body,
  };

  const resultPath = original.result_path;
  if (resultPath) {
    fs.writeFileSync(resultPath, JSON.stringify(result, null, 2), 'utf8');
  }

  output.push({json: result});
}

return output;
